dax_fundamentals.measure_syntax:
// Measures are calculated at query time, adapt to filter context
MeasureName = EXPRESSION
// Example:
Total Sales = SUM(Sales[Amount])

// Measures live in tables but are computed values, not stored columns
// Create via: Modeling tab > New Measure, or right-click table > New Measure

dax_fundamentals.calculated_column_syntax:
// Calculated columns are computed row-by-row at data refresh time, stored in model
// Create via: Modeling tab > New Column
Sales[Margin %] = DIVIDE(Sales[Profit], Sales[Revenue])
Sales[Full Name] = Sales[FirstName] & " " & Sales[LastName]

complete_measures.ytd:
Sales YTD =
    TOTALYTD([Total Sales], 'DateTable'[Date])
// Equivalent to:
// CALCULATE([Total Sales], DATESYTD('DateTable'[Date]))
